arguments.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

// Train the model eagerly so the file exists before the pool is needed
var modelPath = builder.Configuration.GetValue<string>("ML:ModelPath")
    ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
var trainer = new ModelTrainingService(builder.Configuration, LoggerFactory.Create(b => b.AddConsole())
    .CreateLogger<ModelTrainingService>());
trainer.TrainAndEvaluate();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

